using Microsoft.ML;
using Microsoft.ML.Data;
using Microsoft.Extensions.ML;

var builder = WebApplication.CreateBuilder(args);

// --- Train the model at startup ---
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

var rawData = mlContext.Data.LoadFromTextFile<CustomerInput>(
    dataPath, hasHeader: true, separatorChar: ',');

var split = mlContext.Data.TrainTestSplit(rawData, testFraction: 0.2, seed: 42);

var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerInput.Region))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(CustomerInput.Age)))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(CustomerInput.Income)))
    .Append(mlContext.Transforms.NormalizeMinMax(nameof(CustomerInput.PurchaseHistory)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerInput.Age), nameof(CustomerInput.Income),
        "RegionEncoded", nameof(CustomerInput.PurchaseHistory)))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: nameof(CustomerInput.Churned), featureColumnName: "Features"));

var model = pipeline.Fit(split.TrainSet);

// --- Evaluate ---
var predictions = model.Transform(split.TestSet);
var metrics = mlContext.BinaryClassification.Evaluate(predictions,
    labelColumnName: nameof(CustomerInput.Churned));
Console.WriteLine($"Model metrics â€” AUC: {metrics.AreaUnderRocCurve:F4}, " +
    $"Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");

// --- Save & register pooled prediction engine ---
var modelPath = Path.Combine(AppContext.BaseDirectory, "churn-model.zip");
mlContext.Model.Save(model, rawData.Schema, modelPath);

builder.Services.AddPredictionEnginePool<CustomerInput, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API â€” POST /predict with customer data");

app.MapPost("/predict", (PredictionEnginePool<CustomerInput, ChurnPrediction> pool,
    CustomerRequest req) =>
{
    var input = new CustomerInput
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };
    var result = pool.Predict(input);
    return Results.Ok(new
    {
        WillChurn = result.PredictedLabel,
        Probability = result.Probability
    });
});

app.Run();

// --- Data models ---

public class CustomerInput
{
    [LoadColumn(0)] public float Age { get; set; }
    [LoadColumn(1)] public float Income { get; set; }
    [LoadColumn(2)] public string Region { get; set; } = "";
    [LoadColumn(3)] public float PurchaseHistory { get; set; }
    [LoadColumn(4), ColumnName("Churned")]
    public bool Churned { get; set; }
}

public class ChurnPrediction
{
    [ColumnName("PredictedLabel")]
    public bool PredictedLabel { get; set; }
    public float Probability { get; set; }
}

public record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);

